import React, { useState } from "react";
import { Link } from "react-router-dom";
import Layout from "../Layout";
import ListingTable from "../../components/ListingTable/ListingTable";
import useFetch from "../../hooks/useFetch";
import { adminInventoryList } from "../../api/inventory";
import EditIcon from "@mui/icons-material/Edit";

const InventoryList = () => {
  const { apiData, isLoading } = useFetch(adminInventoryList, {});

  const columns = [
    {
      name: "ID",
      selector: (row) => row.id,
      sortable: true,
      width: "70px",
    },
    {
      name: "Product",
      selector: (row) => row.product?.name || "—",
      sortable: true,
    },
    {
      name: "SKU",
      selector: (row) => row.product?.sku || "—",
    },
    {
      name: "Quantity",
      cell: (row) => (
        <span
          style={{
            color: row.is_low_stock ? "#e74c3c" : "inherit",
            fontWeight: row.is_low_stock ? 600 : 400,
          }}
        >
          {row.quantity} {row.is_low_stock && "⚠️"}
        </span>
      ),
    },
    {
      name: "Low Stock Threshold",
      selector: (row) => row.low_stock_threshold,
    },
    {
      name: "Status",
      cell: (row) => (
        <span
          className={`badge ${row.is_low_stock ? "badge-danger" : "badge-success"}`}
        >
          {row.is_low_stock ? "Low Stock" : "In Stock"}
        </span>
      ),
    },
    {
      name: "Actions",
      cell: (row) => (
        <Link
          to={`/inventory/${row.id}/edit`}
          className="btn btn-warning btn-sm action-btn"
        >
          <EditIcon />
        </Link>
      ),
    },
  ];

  return (
    <Layout>
      <div className="d-sm-flex align-items-center justify-content-between mb-4">
        <div>
          <h1 className="h3 mb-2 text-gray-800">Inventory</h1>
          <p className="mb-4">Manage stock levels</p>
        </div>
      </div>

      <div className="card shadow mb-4">
        <div className="card-body">
          {isLoading ? (
            <p>Loading inventory...</p>
          ) : (
            <div className="table-responsive">
              {apiData?.inventory?.length > 0 ? (
                <ListingTable
                  columns={columns}
                  data={apiData.inventory}
                  isLoading={isLoading}
                  filterColumn="product"
                />
              ) : (
                <p>No inventory found.</p>
              )}
            </div>
          )}
        </div>
      </div>
    </Layout>
  );
};

export default InventoryList;
